import{_ as e,o,c as r,ak as i}from"./chunks/framework.C44GrXwr.js";const u=JSON.parse('{"title":"Keyboard Shortcuts","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/extension/keyboard-shortcuts.md","filePath":"documentation/extension/keyboard-shortcuts.md","lastUpdated":1770573358000}'),s={name:"documentation/extension/keyboard-shortcuts.md"};function n(a,t,l,d,c,h){return o(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to “Keyboard Shortcuts”">​</a></h1><p>Trigger extension actions instantly using keyboard shortcuts for faster workflow automation and improved productivity.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Excellent Data Filler provides comprehensive keyboard shortcuts for all major actions. You can customize these shortcuts via Chrome&#39;s extension shortcuts page at <code>chrome://extensions/shortcuts</code>.</p><hr><h2 id="configuring-shortcuts" tabindex="-1">Configuring Shortcuts <a class="header-anchor" href="#configuring-shortcuts" aria-label="Permalink to “Configuring Shortcuts”">​</a></h2><h3 id="access-shortcuts-settings" tabindex="-1">Access Shortcuts Settings <a class="header-anchor" href="#access-shortcuts-settings" aria-label="Permalink to “Access Shortcuts Settings”">​</a></h3><ol><li>Open Chrome and navigate to: <code>chrome://extensions/shortcuts</code></li><li>Find <strong>&quot;Excellent Data Filler&quot;</strong> in the list</li><li>Click on the pencil icon next to any shortcut to customize it</li><li>Press your desired key combination</li><li>Click outside the input to save</li></ol><div class="tip custom-block"><p class="custom-block-title">Customization</p><p>All shortcuts can be customized to your preference. The shortcuts listed below are the default configurations.</p></div><hr><h2 id="available-shortcuts" tabindex="-1">Available Shortcuts <a class="header-anchor" href="#available-shortcuts" aria-label="Permalink to “Available Shortcuts”">​</a></h2><h3 id="extension-control" tabindex="-1">Extension Control <a class="header-anchor" href="#extension-control" aria-label="Permalink to “Extension Control”">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Default Shortcut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Start/Pause</strong></td><td><code>Alt + Q</code></td><td>Start or pause the form automation process</td></tr></tbody></table><p><strong>Use Case:</strong> Quickly start or pause automation without clicking the extension icon.</p><hr><h3 id="form-site-management" tabindex="-1">Form &amp; Site Management <a class="header-anchor" href="#form-site-management" aria-label="Permalink to “Form &amp; Site Management”">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Default Shortcut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Insert Site</strong></td><td><code>Alt + Shift + S</code></td><td>Add a new site configuration</td></tr><tr><td><strong>Insert Form</strong></td><td><code>Alt + Shift + F</code></td><td>Add a new form to the current site</td></tr></tbody></table><p><strong>Use Case:</strong> Rapidly create new site and form configurations while building automation workflows.</p><hr><h3 id="element-inspection" tabindex="-1">Element Inspection <a class="header-anchor" href="#element-inspection" aria-label="Permalink to “Element Inspection”">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Default Shortcut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Inspect Elements</strong></td><td><code>Alt + Shift + I</code></td><td>Open the element inspector tool</td></tr></tbody></table><p><strong>Use Case:</strong> Quickly inspect page elements to identify selectors and XPaths for field configuration.</p><hr><h3 id="copy-operations" tabindex="-1">Copy Operations <a class="header-anchor" href="#copy-operations" aria-label="Permalink to “Copy Operations”">​</a></h3><h4 id="field-response" tabindex="-1">Field &amp; Response <a class="header-anchor" href="#field-response" aria-label="Permalink to “Field &amp; Response”">​</a></h4><table tabindex="0"><thead><tr><th>Action</th><th>Default Shortcut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Copy Field</strong></td><td><code>Alt + C</code></td><td>Copy selected field(s) configuration</td></tr><tr><td><strong>Copy Form Response</strong></td><td><code>Alt + Shift + R</code></td><td>Copy element text, selector, XPath, and URL</td></tr></tbody></table><p><strong>Use Case:</strong> Duplicate field configurations or capture element details for response validation.</p><hr><h4 id="element-properties" tabindex="-1">Element Properties <a class="header-anchor" href="#element-properties" aria-label="Permalink to “Element Properties”">​</a></h4><table tabindex="0"><thead><tr><th>Action</th><th>Default Shortcut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Copy Element Selector</strong></td><td><code>Alt + Shift + C</code></td><td>Copy CSS selector of selected element</td></tr><tr><td><strong>Copy Element XPath</strong></td><td><code>Alt + Shift + X</code></td><td>Copy XPath of selected element</td></tr><tr><td><strong>Copy Element Text</strong></td><td><code>Alt + Shift + T</code></td><td>Copy text content of selected element</td></tr><tr><td><strong>Copy Element HTML</strong></td><td><code>Alt + Shift + H</code></td><td>Copy HTML content of selected element</td></tr></tbody></table><p><strong>Use Case:</strong> Quickly extract element properties for field configuration or debugging.</p><hr><h4 id="select-options" tabindex="-1">Select Options <a class="header-anchor" href="#select-options" aria-label="Permalink to “Select Options”">​</a></h4><table tabindex="0"><thead><tr><th>Action</th><th>Default Shortcut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Copy Option Name</strong></td><td><code>Alt + Shift + N</code></td><td>Copy the name/label of a select option</td></tr><tr><td><strong>Copy Option Value</strong></td><td><code>Alt + Shift + M</code></td><td>Copy the value attribute of a select option</td></tr></tbody></table><p><strong>Use Case:</strong> Extract dropdown option details for form automation configuration.</p><hr><h2 id="complete-shortcuts-reference" tabindex="-1">Complete Shortcuts Reference <a class="header-anchor" href="#complete-shortcuts-reference" aria-label="Permalink to “Complete Shortcuts Reference”">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Shortcut</th><th>Category</th></tr></thead><tbody><tr><td><strong>Start/Pause</strong></td><td><code>Alt + Q</code></td><td>Control</td></tr><tr><td><strong>Inspect Elements</strong></td><td><code>Alt + Shift + I</code></td><td>Inspection</td></tr><tr><td><strong>Insert Site</strong></td><td><code>Alt + Shift + S</code></td><td>Management</td></tr><tr><td><strong>Insert Form</strong></td><td><code>Alt + Shift + F</code></td><td>Management</td></tr><tr><td><strong>Copy Field</strong></td><td><code>Alt + C</code></td><td>Copy</td></tr><tr><td><strong>Copy Form Response</strong></td><td><code>Alt + Shift + R</code></td><td>Copy</td></tr><tr><td><strong>Copy Element Selector</strong></td><td><code>Alt + Shift + C</code></td><td>Copy</td></tr><tr><td><strong>Copy Element XPath</strong></td><td><code>Alt + Shift + X</code></td><td>Copy</td></tr><tr><td><strong>Copy Element Text</strong></td><td><code>Alt + Shift + T</code></td><td>Copy</td></tr><tr><td><strong>Copy Element HTML</strong></td><td><code>Alt + Shift + H</code></td><td>Copy</td></tr><tr><td><strong>Copy Option Name</strong></td><td><code>Alt + Shift + N</code></td><td>Copy</td></tr><tr><td><strong>Copy Option Value</strong></td><td><code>Alt + Shift + M</code></td><td>Copy</td></tr></tbody></table><hr><h2 id="shortcut-patterns" tabindex="-1">Shortcut Patterns <a class="header-anchor" href="#shortcut-patterns" aria-label="Permalink to “Shortcut Patterns”">​</a></h2><h3 id="modifier-keys" tabindex="-1">Modifier Keys <a class="header-anchor" href="#modifier-keys" aria-label="Permalink to “Modifier Keys”">​</a></h3><p>All shortcuts use <strong>Alt</strong> as the primary modifier key:</p><ul><li><code>Alt + [Key]</code> - Primary actions (Start/Pause, Copy Field)</li><li><code>Alt + Shift + [Key]</code> - Secondary actions (Inspect, Insert, Copy Element Properties)</li></ul><div class="info custom-block"><p class="custom-block-title">Consistency</p><p>The shortcut pattern is designed for easy memorization:</p><ul><li><strong>Alt + Q</strong> - Quick start/pause</li><li><strong>Alt + C</strong> - Copy field</li><li><strong>Alt + Shift + [Letter]</strong> - Specific copy actions (C=Selector, X=XPath, T=Text, etc.)</li></ul></div><hr><h2 id="tips-best-practices" tabindex="-1">Tips &amp; Best Practices <a class="header-anchor" href="#tips-best-practices" aria-label="Permalink to “Tips &amp; Best Practices”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Memorization</p><p>Focus on learning the most frequently used shortcuts first:</p><ol><li><code>Alt + Q</code> - Start/Pause</li><li><code>Alt + Shift + I</code> - Inspect Elements</li><li><code>Alt + Shift + C</code> - Copy Selector</li><li><code>Alt + Shift + X</code> - Copy XPath</li></ol></div><div class="warning custom-block"><p class="custom-block-title">Conflicts</p><p>If a shortcut conflicts with another extension or browser feature, customize it at <code>chrome://extensions/shortcuts</code>.</p></div><div class="info custom-block"><p class="custom-block-title">Global vs In-Extension</p><p>Some shortcuts work globally (anywhere in Chrome), while others only work when the extension popup is open or when inspecting elements.</p></div><div class="tip custom-block"><p class="custom-block-title">Workflow Efficiency</p><p>Combine shortcuts with the <a href="./context-menu.html">Context Menu</a> for maximum productivity. Use shortcuts for frequent actions and context menu for occasional tasks.</p></div><hr><h2 id="common-workflows" tabindex="-1">Common Workflows <a class="header-anchor" href="#common-workflows" aria-label="Permalink to “Common Workflows”">​</a></h2><h3 id="quick-element-inspection" tabindex="-1">Quick Element Inspection <a class="header-anchor" href="#quick-element-inspection" aria-label="Permalink to “Quick Element Inspection”">​</a></h3><ol><li>Press <code>Alt + Shift + I</code> to open inspector</li><li>Hover over target element</li><li>Press <code>Alt + Shift + C</code> to copy selector</li><li>Or press <code>Alt + Shift + X</code> to copy XPath</li><li>Paste into field configuration</li></ol><hr><h3 id="rapid-form-building" tabindex="-1">Rapid Form Building <a class="header-anchor" href="#rapid-form-building" aria-label="Permalink to “Rapid Form Building”">​</a></h3><ol><li>Press <code>Alt + Shift + S</code> to insert new site</li><li>Press <code>Alt + Shift + F</code> to insert new form</li><li>Configure fields using element inspection</li><li>Press <code>Alt + C</code> to copy fields for reuse</li><li>Press <code>Alt + Q</code> to start automation</li></ol><hr><h3 id="response-validation-setup" tabindex="-1">Response Validation Setup <a class="header-anchor" href="#response-validation-setup" aria-label="Permalink to “Response Validation Setup”">​</a></h3><ol><li>Submit a test form</li><li>Press <code>Alt + Shift + R</code> on success/error message</li><li>Paste captured data into response settings</li><li>Configure validation rules</li><li>Test with <code>Alt + Q</code></li></ol><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><h3 id="shortcut-not-working" tabindex="-1">Shortcut Not Working <a class="header-anchor" href="#shortcut-not-working" aria-label="Permalink to “Shortcut Not Working”">​</a></h3><p><strong>Possible Causes:</strong></p><ul><li>Shortcut conflicts with another extension</li><li>Browser focus is not on the correct element</li><li>Shortcut is disabled in Chrome settings</li></ul><p><strong>Solutions:</strong></p><ol><li>Check <code>chrome://extensions/shortcuts</code> for conflicts</li><li>Ensure the extension is enabled</li><li>Try customizing the shortcut to a different key combination</li><li>Restart Chrome if shortcuts stop working</li></ol><hr><h3 id="customizing-shortcuts" tabindex="-1">Customizing Shortcuts <a class="header-anchor" href="#customizing-shortcuts" aria-label="Permalink to “Customizing Shortcuts”">​</a></h3><p><strong>Steps:</strong></p><ol><li>Navigate to <code>chrome://extensions/shortcuts</code></li><li>Find &quot;Excellent Data Filler&quot;</li><li>Click the pencil icon next to the shortcut</li><li>Press your desired key combination</li><li>Ensure no conflicts with existing shortcuts</li><li>Click outside to save</li></ol><p><strong>Recommendations:</strong></p><ul><li>Use modifier keys (Alt, Ctrl, Shift) to avoid conflicts</li><li>Keep shortcuts memorable and related to their function</li><li>Test shortcuts after customization</li></ul><hr><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to “Related Documentation”">​</a></h2><ul><li><a href="./context-menu.html">Context Menu</a> - Right-click menu actions</li></ul>',76)])])}const m=e(s,[["render",n]]);export{u as __pageData,m as default};
